scwin.ed_srchFixedAsetNo_onblur = function (e) {
    if(!$c.gus.cfIsNull(ed_srchFixedAsetNo.getValue())) {
		let value = $c.gus.cfGetLeftPad(ed_srchFixedAsetNo.getValue(), 10);
        ed_srchFixedAsetNo.setValue(value);
    }
};

scwin.ed_srchFixedAsetNo2_onblur = function (e) {
    if(!$c.gus.cfIsNull(ed_srchFixedAsetNo2.getValue())) {
